    int n = prices.length;
    int kInt = (int) k;
    int halfK = kInt / 2;

    long[] prefixA = new long[n+1];
    long[] prefixB = new long[n+1];
    for (int i = 0; i < n; i++) {
        prefixA[i+1] = prefixA[i] + strategy[i] * prices[i];
        prefixB[i+1] = prefixB[i] + prices[i];
    }

    long baseProfit = prefixA[n];
    long maxProfit = baseProfit;

    for (int l = 0; l <= n - kInt; l++) {
        long base_segment = prefixA[l+kInt] - prefixA[l];
        long added = prefixB[l+kInt] - prefixB[l+halfK];
        long candidate = baseProfit - base_segment + added;
        if (candidate > maxProfit) {
            maxProfit = candidate;
        }
    }

    return maxProfit;
}
